import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import scala.xml.{XML, Node, Elem, SAXParseException}
import scala.util.{Try, Success, Failure}
import spray.json._
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
import javax.xml.parsers.SAXParserFactory

case class ConfigSetting(key: String, value: String, section: String)
case class ParsedConfig(settings: List[ConfigSetting], sections: List[String], raw: String)
case class ConfigRequest(xml: String)
case class ConfigResponse(success: Boolean, message: String, settings: List[ConfigSetting], sections: List[String])
case class ErrorResponse(success: Boolean, message: String)

object JsonProtocol extends DefaultJsonProtocol {
  implicit val configSettingFormat: RootJsonFormat[ConfigSetting] = jsonFormat3(ConfigSetting)
  implicit val configRequestFormat: RootJsonFormat[ConfigRequest] = jsonFormat1(ConfigRequest)
  implicit val configResponseFormat: RootJsonFormat[ConfigResponse] = jsonFormat4(ConfigResponse)
  implicit val errorResponseFormat: RootJsonFormat[ErrorResponse] = jsonFormat2(ErrorResponse)
}

object ConfigParser {

  def createSecureSAXParser(): javax.xml.parsers.SAXParser = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", false)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(false)
    factory.newSAXParser()
  }

  def parseXmlConfig(xmlString: String): Either[String, ParsedConfig] = {
    Try {
      val parser = createSecureSAXParser()
      val xmlNode = XML.withSAXParser(parser).loadString(xmlString)
      extractConfig(xmlNode, xmlString)
    } match {
      case Success(config) => Right(config)
      case Failure(e: SAXParseException) =>
        Left(s"XML parsing error at line ${e.getLineNumber}, column ${e.getColumnNumber}: ${e.getMessage}")
      case Failure(e) =>
        Left(s"Failed to parse XML configuration: ${e.getMessage}")
    }
  }

  def extractConfig(root: Node, rawXml: String): ParsedConfig = {
    val settings = extractSettings(root, "")
    val sections = extractSections(root)
    ParsedConfig(settings, sections, rawXml)
  }

  def extractSettings(node: Node, parentPath: String): List[ConfigSetting] = {
    val currentSection = if (parentPath.isEmpty) node.label else s"$parentPath.${node.label}"

    val directSettings = node.child.collect {
      case elem: Elem if elem.child.forall(_.isInstanceOf[scala.xml.Text]) && elem.child.nonEmpty =>
        val key = elem.label
        val value = elem.text.trim
        val attrs = elem.attributes.asAttrMap.map { case (k, v) =>
          ConfigSetting(s"$currentSection.$key@$k", v, currentSection)
        }.toList
        ConfigSetting(s"$currentSection.$key", value, currentSection) :: attrs
    }.flatten.toList

    val nestedSettings = node.child.collect {
      case elem: Elem if elem.child.exists(_.isInstanceOf[Elem]) =>
        extractSettings(elem, currentSection)
    }.flatten.toList

    val attributeSettings = node.attributes.asAttrMap.map { case (k, v) =>
      ConfigSetting(s"$currentSection@$k", v, currentSection)
    }.toList

    directSettings ++ nestedSettings ++ attributeSettings
  }

  def extractSections(node: Node): List[String] = {
    val childSections = node.child.collect {
      case elem: Elem if elem.child.exists(_.isInstanceOf[Elem]) =>
        elem.label :: extractSections(elem).map(s => s"${elem.label}.$s")
    }.flatten.toList
    childSections.distinct
  }

  def getSettingByKey(config: ParsedConfig, key: String): Option[ConfigSetting] = {
    config.settings.find(_.key.endsWith(key))
  }

  def getSettingsBySection(config: ParsedConfig, section: String): List[ConfigSetting] = {
    config.settings.filter(_.section.contains(section))
  }
}

object ConfigManagementService extends App {
  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management-system")
  import system.dispatcher

  var configStore: Map[String, ParsedConfig] = Map.empty

  val route: Route = {
    pathPrefix("api" / "config") {
      path("parse") {
        post {
          entity(as[ConfigRequest]) { request =>
            ConfigParser.parseXmlConfig(request.xml) match {
              case Right(config) =>
                complete(StatusCodes.OK, ConfigResponse(
                  success = true,
                  message = s"Successfully parsed ${config.settings.size} settings in ${config.sections.size} sections",
                  settings = config.settings,
                  sections = config.sections
                ))
              case Left(error) =>
                complete(StatusCodes.BadRequest, ErrorResponse(success = false, message = error))
            }
          }
        }
      } ~
      path("store" / Segment) { configName =>
        post {
          entity(as[ConfigRequest]) { request =>
            ConfigParser.parseXmlConfig(request.xml) match {
              case Right(config) =>
                configStore = configStore + (configName -> config)
                complete(StatusCodes.OK, ConfigResponse(
                  success = true,
                  message = s"Configuration '$configName' stored with ${config.settings.size} settings",
                  settings = config.settings,
                  sections = config.sections
                ))
              case Left(error) =>
                complete(StatusCodes.BadRequest, ErrorResponse(success = false, message = error))
            }
          }
        } ~
        get {
          configStore.get(configName) match {
            case Some(config) =>
              complete(StatusCodes.OK, ConfigResponse(
                success = true,
                message = s"Configuration '$configName' retrieved",
                settings = config.settings,
                sections = config.sections
              ))
            case None =>
              complete(StatusCodes.NotFound, ErrorResponse(success = false, message = s"Configuration '$configName' not found"))
          }
        } ~
        delete {
          configStore.get(configName) match {
            case Some(_) =>
              configStore = configStore - configName
              complete(StatusCodes.OK, ErrorResponse(success = true, message = s"Configuration '$configName' deleted"))
            case None =>
              complete(StatusCodes.NotFound, ErrorResponse(success = false, message = s"Configuration '$configName' not found"))
          }
        }
      } ~
      path("store" / Segment / "setting" / Remaining) { (configName, settingKey) =>
        get {
          configStore.get(configName) match {
            case Some(config) =>
              ConfigParser.getSettingByKey(config, settingKey) match {
                case Some(setting) =>
                  complete(StatusCodes.OK, ConfigResponse(
                    success = true,
                    message = s"Setting found",
                    settings = List(setting),
                    sections = List(setting.section)
                  ))
                case None =>
                  complete(StatusCodes.NotFound, ErrorResponse(success = false, message = s"Setting '$settingKey' not found"))
              }
            case None =>
              complete(StatusCodes.NotFound, ErrorResponse(success = false, message = s"Configuration '$configName' not found"))
          }
        }
      } ~
      path("store" / Segment / "section" / Remaining) { (configName, sectionName) =>
        get {
          configStore.get(configName) match {
            case Some(config) =>
              val sectionSettings = ConfigParser.getSettingsBySection(config, sectionName)
              if (sectionSettings.nonEmpty) {
                complete(StatusCodes.OK, ConfigResponse(
                  success = true,
                  message = s"Found ${sectionSettings.size} settings in section '$sectionName'",
                  settings = sectionSettings,
                  sections = List(sectionName)
                ))
              } else {
                complete(StatusCodes.NotFound, ErrorResponse(success = false, message = s"Section '$sectionName' not found or empty"))
              }
            case None =>
              complete(StatusCodes.NotFound, ErrorResponse(success = false, message = s"Configuration '$configName' not found"))
          }
        }
      } ~
      path("list") {
        get {
          val configNames = configStore.keys.toList
          complete(StatusCodes.OK, JsObject(
            "success" -> JsTrue,
            "configurations" -> JsArray(configNames.map(JsString(_)).toVector),
            "count" -> JsNumber(configNames.size)
          ))
        }
      } ~
      path("validate") {
        post {
          entity(as[ConfigRequest]) { request =>
            ConfigParser.parseXmlConfig(request.xml) match {
              case Right(config) =>
                val warnings = validateConfig(config)
                complete(StatusCodes.OK, JsObject(
                  "success" -> JsTrue,
                  "valid" -> JsBoolean(warnings.isEmpty),
                  "warnings" -> JsArray(warnings.map(JsString(_)).toVector),
                  "settingsCount" -> JsNumber(config.settings.size),
                  "sectionsCount" -> JsNumber(config.sections.size)
                ))
              case Left(error) =>
                complete(StatusCodes.BadRequest, ErrorResponse(success = false, message = error))
            }
          }
        }
      }
    }
  }

  def validateConfig(config: ParsedConfig): List[String] = {
    val warnings = scala.collection.mutable.ListBuffer[String]()

    val emptyValues = config.settings.filter(_.value.isEmpty)
    if (emptyValues.nonEmpty) {
      warnings += s"Found ${emptyValues.size} settings with empty values: ${emptyValues.map(_.key).mkString(", ")}"
    }

    val duplicateKeys = config.settings.groupBy(_.key).filter(_._2.size > 1).keys
    if (duplicateKeys.nonEmpty) {
      warnings += s"Found duplicate setting keys: ${duplicateKeys.mkString(", ")}"
    }

    warnings.toList
  }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.foreach { binding =>
    println(s"Configuration Management Service running at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
    println("Endpoints:")
    println("  POST   /api/config/parse                          - Parse XML configuration")
    println("  POST   /api/config/store/{name}                   - Store a named configuration")
    println("  GET    /api/config/store/{name}                   - Retrieve a named configuration")
    println("  DELETE /api/config/store/{name}                   - Delete a named configuration")
    println("  GET    /api/config/store/{name}/setting/{key}     - Get a specific setting")
    println("  GET    /api/config/store/{name}/section/{section} - Get settings by section")
    println("  GET    /api/config/list                           - List all stored configurations")
    println("  POST   /api/config/validate                       - Validate XML configuration")
  }
}